const news = $('Get NewsAPI Articles').first().json.articles || [];
const existing = $('Get Existing Queue Rows').all().map(i=>i.json);
const seen = new Set(existing.map(r => String(r.source_url || '').toLowerCase()).filter(Boolean));
const clean=s=>String(s||'').replace(/\s+/g,' ').trim();
const include=['hiking','hiker','trail','backcountry','national park','climb','climbing','mountain','mountaineer','avalanche','ski','snowpack','outdoor','rescue','wilderness','camping'];
const exclude=['stock','stocks','market','fed','interest rate','mortgage','crypto','earnings','consumer confidence','oil price','finance','financial'];
const out=[];
for (const a of news){
 const title=clean(a.title), desc=clean(a.description), url=clean(a.url), image=clean(a.urlToImage), source=clean(a.source?.name)||'NewsAPI';
 if(!title||!url||!image) continue;
 const text=(title+' '+desc).toLowerCase();
 if(exclude.some(x=>text.includes(x))) continue;
 if(include.filter(x=>text.includes(x)).length===0) continue;
 if(seen.has(url.toLowerCase())) continue;
 seen.add(url.toLowerCase());
 const prompt = 'You are filtering articles for the Mildly Outdoorsy Instagram brand. '+
 'Brand fit: hiking, trails, national parks, climbing, ski/backcountry, mountain safety, outdoor rescue, wilderness culture. '+
 'Reject finance, politics, generic business news unless directly outdoors-relevant. '+
 'Audience context: outdoors-first people who scroll fast and only stop for high-stakes, useful, emotionally vivid stories. '+
 'Writing objective: maximize swipe-through on a 5-slide carousel by turning the article into a tight narrative arc. '+
 'Narrative requirements: slide2=what happened (scene + stakes), slide3=why it matters (impact + consequence), slide4=what to do/learn (practical takeaway), slide5=payoff/next-step/CTA that feels earned. '+
 'Hook requirement: the first-card headline must be a thumb-stopping sentence with urgency/curiosity, no clickbait lies. '+
 'Style constraints: concrete details over generic phrasing, active voice, short punchy lines, no hashtags in slide text. '+
 'Given article. Title: '+title+' Description: '+desc+' Source: '+source+' URL: '+url+' '+
 'Return STRICT JSON only with keys: keep(boolean), reason(string), headline_text(string <=140 chars), slide2_text(string <=220), slide3_text(string <=220), slide4_text(string <=220), slide5_text(string <=220), caption(string <=500).';
 out.push({json:{title,desc,url,image,source,prompt}});
 if(out.length>=10) break;
}
return out;

return $input.all().map((item, idx) => {
  const src = $('Build Candidate Articles').all()[idx]?.json || {};
  let parsed = { keep: false, reason: 'parse_failed' };
  try {
    // Handle OpenAI chat completion response
    const raw = item.json?.choices?.[0]?.message?.content
      ?? item.json?.result
      ?? null;
    if (raw) {
      parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
    }
  } catch(e) {
    parsed = { keep: false, reason: 'json_parse_error: ' + e.message };
  }
  return { json: { ...src, ...parsed } };
});

return $input.all().slice(0,3).map(i=>{
  const j=i.json;
  const headline=String(j.headline_text||j.title||'').trim();
  return {json:{
    status:'pending',
    queue_status:'pending',
    content_type:'twitter_card_balanced',
    shirt_name:'newsapi',
    headline_text:headline,
    slide_1_main_text:headline,
    slide_1_sub_text:'Source: '+(j.source||'NewsAPI'),
    slide_2_main_text:j.slide2_text||'',
    slide_3_main_text:j.slide3_text||'',
    slide_4_main_text:j.slide4_text||'',
    slide_5_main_text:j.slide5_text||'',
    caption:j.caption||[headline,'Source: '+(j.source||'NewsAPI'),j.url].join('\n\n'),
    source_name:j.source||'NewsAPI',
    source_image_url:j.image,
    source_url:j.url
  }};
});
